func (fx *FeaturestoreServiceFeatureTestSuiteConfig) testUpdate(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if no name is provided.
	t.Run("missing name", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		msg := fx.Update(parent)
		msg.SetName("")
		req := &UpdateFeatureRequest{}
		req.SetFeature(msg)
		_, err := fx.Service().UpdateFeature(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument if provided name is not valid.
	t.Run("invalid name", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		msg := fx.Update(parent)
		msg.SetName("invalid resource name")
		req := &UpdateFeatureRequest{}
		req.SetFeature(msg)
		_, err := fx.Service().UpdateFeature(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// The updated resource should be persisted and reachable with Get.
	t.Run("persisted", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		updateReq := &UpdateFeatureRequest{}
		updateReq.SetFeature(created)
		updated, err := fx.Service().UpdateFeature(fx.Context(), updateReq)
		assert.NilError(t, err)
		getReq := &GetFeatureRequest{}
		getReq.SetName(updated.GetName())
		persisted, err := fx.Service().GetFeature(fx.Context(), getReq)
		assert.NilError(t, err)
		assert.DeepEqual(t, updated, persisted, protocmp.Transform())
	})

	// Method should fail with Aborted if the supplied etag doesnt match the current etag value.
	t.Run("etag mismatch", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		msg := fx.Update(parent)
		msg.SetName(created.GetName())
		msg.SetEtag(`"99999"`)
		req := &UpdateFeatureRequest{}
		req.SetFeature(msg)
		_, err := fx.Service().UpdateFeature(fx.Context(), req)
		assert.Equal(t, codes.Aborted, status.Code(err), err)
	})

	// Field etag should have a new value when the resource is successfully updated.
	t.Run("etag updated", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		msg := fx.Update(parent)
		msg.SetName(created.GetName())
		msg.SetEtag(created.GetEtag())
		req := &UpdateFeatureRequest{}
		req.SetFeature(msg)
		updated, err := fx.Service().UpdateFeature(fx.Context(), req)
		assert.NilError(t, err)
		assert.Check(t, updated.GetEtag() != created.GetEtag())
	})

	{
		parent := fx.nextParent(t, false)
		created := fx.create(t, parent)
		// Method should fail with NotFound if the resource does not exist.
		t.Run("not found", func(t *testing.T) {
			fx.maybeSkip(t)
			msg := fx.Update(parent)
			msg.SetName(created.GetName() + "notfound")
			req := &UpdateFeatureRequest{}
			req.SetFeature(msg)
			_, err := fx.Service().UpdateFeature(fx.Context(), req)
			assert.Equal(t, codes.NotFound, status.Code(err), err)
		})

		// The method should fail with InvalidArgument if the update_mask is invalid.
		t.Run("invalid update mask", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &UpdateFeatureRequest{}
			req.SetFeature(created)
			req.SetUpdateMask(&fieldmaskpb.FieldMask{
				Paths: []string{
					"invalid_field_xyz",
				},
			})
			_, err := fx.Service().UpdateFeature(fx.Context(), req)
			assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
		})

	}
}

func (fx *FeaturestoreServiceFeatureTestSuiteConfig) testList(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if provided parent is invalid.
	t.Run("invalid parent", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &ListFeaturesRequest{}
		req.SetParent("invalid resource name")
		_, err := fx.Service().ListFeatures(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument is provided page token is not valid.
	t.Run("invalid page token", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		req := &ListFeaturesRequest{}
		req.SetParent(parent)
		req.SetPageToken("invalid page token")
		_, err := fx.Service().ListFeatures(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument is provided page size is negative.
	t.Run("negative page size", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		req := &ListFeaturesRequest{}
		req.SetParent(parent)
		req.SetPageSize(-10)
		_, err := fx.Service().ListFeatures(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	{
		const resourcesCount = 5
		parent := fx.nextParent(t, true)
		parentMsgs := make([]*Feature, resourcesCount)
		for i := 0; i < resourcesCount; i++ {
			parentMsgs[i] = fx.create(t, parent)
		}

		// If parent is provided the method must only return resources
		// under that parent.
		t.Run("isolation", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &ListFeaturesRequest{}
			req.SetParent(parent)
			req.SetPageSize(999)
			response, err := fx.Service().ListFeatures(fx.Context(), req)
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				parentMsgs,
				response.GetFeatures(),
				cmpopts.SortSlices(func(a, b *Feature) bool {
					return a.GetName() < b.GetName()
				}),
				protocmp.Transform(),
			)
		})

		// If there are no more resources, next_page_token should not be set.
		t.Run("last page", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &ListFeaturesRequest{}
			req.SetParent(parent)
			req.SetPageSize(resourcesCount)
			response, err := fx.Service().ListFeatures(fx.Context(), req)
			assert.NilError(t, err)
			assert.Equal(t, "", response.GetNextPageToken())
		})

		// If there are more resources, next_page_token should be set.
		t.Run("more pages", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &ListFeaturesRequest{}
			req.SetParent(parent)
			req.SetPageSize(resourcesCount - 1)
			response, err := fx.Service().ListFeatures(fx.Context(), req)
			assert.NilError(t, err)
			assert.Check(t, response.GetNextPageToken() != "")
		})

		// Listing resource one by one should eventually return all resources.
		t.Run("one by one", func(t *testing.T) {
			fx.maybeSkip(t)
			msgs := make([]*Feature, 0, resourcesCount)
			var nextPageToken string
			for {
				req := &ListFeaturesRequest{}
				req.SetParent(parent)
				req.SetPageSize(1)
				req.SetPageToken(nextPageToken)
				response, err := fx.Service().ListFeatures(fx.Context(), req)
				assert.NilError(t, err)
				assert.Equal(t, 1, len(response.GetFeatures()))
				msgs = append(msgs, response.GetFeatures()...)
				nextPageToken = response.GetNextPageToken()
				if nextPageToken == "" {
					break
				}
			}
			assert.DeepEqual(
				t,
				parentMsgs,
				msgs,
				cmpopts.SortSlices(func(a, b *Feature) bool {
					return a.GetName() < b.GetName()
				}),
				protocmp.Transform(),
			)
		})

		// When listing resource with page size zero the service should use a default value.
		t.Run("page size zero", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &ListFeaturesRequest{}
			req.SetParent(parent)
			req.SetPageSize(0)
			response, err := fx.Service().ListFeatures(fx.Context(), req)
			assert.NilError(t, err)
			// Server should use a default page size and return at least some results
			assert.Check(t, len(response.GetFeatures()) > 0, "expected server to return at least 1 resource with page_size=0")
		})

	}
	{
		const resourcesCount = 5
		parent := fx.nextParent(t, true)
		parentMsgs := make([]*Feature, resourcesCount)
		for i := 0; i < resourcesCount; i++ {
			parentMsgs[i] = fx.create(t, parent)
		}

		// Method should not return deleted resources.
		t.Run("deleted", func(t *testing.T) {
			fx.maybeSkip(t)
			const deleteCount = 3
			for i := 0; i < deleteCount; i++ {
				delReq := &DeleteFeatureRequest{}
				delReq.SetName(parentMsgs[i].GetName())
				_, err := fx.Service().DeleteFeature(fx.Context(), delReq)
				assert.NilError(t, err)
			}
			listReq := &ListFeaturesRequest{}
			listReq.SetParent(parent)
			listReq.SetPageSize(9999)
			response, err := fx.Service().ListFeatures(fx.Context(), listReq)
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				parentMsgs[deleteCount:],
				response.GetFeatures(),
				cmpopts.SortSlices(func(a, b *Feature) bool {
					return a.GetName() < b.GetName()
				}),
				protocmp.Transform(),
			)
		})

	}
}

